import React, { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { Link, useNavigate } from "react-router-dom";
import {
  removeFromB2bCart,
  updateB2bCartQty,
  clearB2bCart,
  getB2bProfile,
} from "../../features/b2b/b2bSlice";
import B2bLayout from "./B2bLayout";
import {
  Trash2, Plus, Minus, ShoppingCart, ArrowRight,
  Package, AlertCircle, Layers, ArrowLeft
} from "lucide-react";

const B2bCart = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { cart, profile } = useSelector((s) => s.b2b);

  useEffect(() => {
    if (!profile) {
      dispatch(getB2bProfile());
    }
  }, [dispatch, profile]);

  const getUnitPrice = (item) => {
    const tiers = item.product.tierPricing || [];
    if (tiers.length > 0) {
      const sorted = [...tiers].sort((a, b) => b.minQty - a.minQty);
      const match = sorted.find((t) => item.quantity >= t.minQty);
      if (match) return parseFloat(match.unitPrice);
    }
    return parseFloat(item.product.wholesalePrice || 0);
  };

  const subtotal = cart.reduce((sum, item) => sum + getUnitPrice(item) * item.quantity, 0);

  if (cart.length === 0) {
    return (
      <B2bLayout>
        <div className="flex flex-col items-center justify-center py-28 bg-white rounded-3xl border border-slate-100 shadow-sm">
          <div className="w-20 h-20 bg-slate-50 rounded-3xl flex items-center justify-center mb-6">
            <ShoppingCart size={36} className="text-slate-300" />
          </div>
          <h2 className="text-xl font-black text-slate-800 mb-2">Your Procurement Cart is Empty</h2>
          <p className="text-sm text-slate-500 font-medium mb-6">
            Browse the catalog and add medical supplies to get started.
          </p>
          <Link
            to="/b2b"
            className="bg-blue-600 text-white px-8 py-3 rounded-2xl font-black text-sm uppercase tracking-wider hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200"
          >
            Browse Catalog
          </Link>
        </div>
      </B2bLayout>
    );
  }

  return (
    <B2bLayout>
      <div className="flex items-center justify-between mb-8">
        <div>
          <Link
            to="/b2b"
            className="flex items-center gap-1.5 text-sm font-bold text-slate-400 hover:text-blue-600 transition-colors mb-2"
          >
            <ArrowLeft size={16} /> Continue Shopping
          </Link>
          <h1 className="text-2xl font-black text-slate-900">
            Procurement Cart
            <span className="text-sm font-bold text-slate-400 ml-3">
              {cart.length} {cart.length === 1 ? "item" : "items"}
            </span>
          </h1>
        </div>
        <button
          onClick={() => dispatch(clearB2bCart())}
          className="text-xs font-bold text-rose-500 hover:text-rose-700 bg-rose-50 px-4 py-2 rounded-xl transition-colors"
        >
          Clear Cart
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Cart Items */}
        <div className="lg:col-span-2 flex flex-col gap-4">
          {cart.map((item) => {
            const moq = item.product.minimumOrderQuantity || 1;
            const caseQty = item.product.caseQuantity || 1;
            const step = caseQty > 1 ? caseQty : 1;
            const unitPrice = getUnitPrice(item);
            const lineTotal = unitPrice * item.quantity;
            const img = item.product.images?.[0];
            const isCaseMultiple = item.quantity % step === 0;

            return (
              <div
                key={item.product.id}
                className="bg-white rounded-3xl border border-slate-100 p-5 flex gap-5 shadow-sm hover:shadow-md transition-shadow"
              >
                {/* Image */}
                <div className="w-24 h-24 rounded-2xl bg-slate-50 flex-shrink-0 overflow-hidden flex items-center justify-center">
                  {img || item.product.colors?.[0]?.images?.[0] ? (
                    <img
                      src={
                        img?.secure_url ||
                        img?.url ||
                        (typeof img === "string" ? img : "") ||
                        item.product.colors?.[0]?.images?.[0]?.secure_url ||
                        item.product.colors?.[0]?.images?.[0]?.url ||
                        (typeof item.product.colors?.[0]?.images?.[0] === "string" ? item.product.colors[0].images[0] : "")
                      }
                      alt={item.product.title}
                      className="w-full h-full object-cover"
                    />
                  ) : (
                    <Layers size={28} className="text-slate-300" />
                  )}
                </div>

                {/* Details */}
                <div className="flex-1 flex flex-col justify-between min-w-0">
                  <div>
                    <Link
                      to={`/b2b/product/${item.product.id}`}
                      className="font-extrabold text-slate-900 hover:text-blue-600 transition-colors truncate block"
                    >
                      {item.product.title}
                    </Link>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">
                      SKU: {item.product.sku || "N/A"} &bull; {item.product.unitOfSale || "Standard"}
                    </p>
                  </div>

                  <div className="flex items-center gap-4 mt-3">
                    <div className="flex items-center bg-slate-50 rounded-xl border border-slate-200">
                      <button
                        onClick={() =>
                          dispatch(updateB2bCartQty({ id: item.product.id, quantity: Math.max(moq, item.quantity - step) }))
                        }
                        className="w-9 h-9 flex items-center justify-center text-slate-400 hover:text-blue-600"
                      >
                        <Minus size={14} />
                      </button>
                      <input
                        type="number"
                        value={item.quantity}
                        min={moq}
                        step={step}
                        onChange={(e) => {
                          let val = Math.max(moq, parseInt(e.target.value) || moq);
                          if (caseQty > 1) {
                            val = Math.ceil(val / caseQty) * caseQty;
                          }
                          dispatch(updateB2bCartQty({ id: item.product.id, quantity: val }));
                        }}
                        className="w-16 text-center text-sm font-extrabold bg-transparent border-0 focus:outline-none"
                      />
                      <button
                        onClick={() =>
                          dispatch(updateB2bCartQty({ id: item.product.id, quantity: item.quantity + step }))
                        }
                        className="w-9 h-9 flex items-center justify-center text-slate-400 hover:text-blue-600"
                      >
                        <Plus size={14} />
                      </button>
                    </div>

                    {item.quantity < moq && (
                      <span className="text-[10px] font-bold text-amber-600 flex items-center gap-1">
                        <AlertCircle size={12} /> MOQ: {moq}
                      </span>
                    )}
                    {caseQty > 1 && !isCaseMultiple && (
                      <span className="text-[10px] font-bold text-rose-600 flex items-center gap-1">
                        <AlertCircle size={12} /> Must be multiple of {caseQty}
                      </span>
                    )}
                  </div>
                </div>

                {/* Price & Remove */}
                <div className="flex flex-col items-end justify-between flex-shrink-0">
                  <button
                    onClick={() => dispatch(removeFromB2bCart(item.product.id))}
                    className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-colors"
                  >
                    <Trash2 size={16} />
                  </button>
                  <div className="text-right">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">
                      {unitPrice.toLocaleString()} × {item.quantity}
                    </span>
                    <span className="text-lg font-black text-slate-950">
                      {lineTotal.toLocaleString()} <span className="text-xs text-slate-400">ETB</span>
                    </span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Order Summary */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm sticky top-28">
            <h3 className="text-sm font-black text-slate-600 uppercase tracking-wider mb-6 flex items-center gap-2">
              <Package size={16} /> Order Summary
            </h3>

            <div className="space-y-3 border-b border-slate-100 pb-5 mb-5">
              {cart.map((item) => (
                <div key={item.product.id} className="flex justify-between text-sm">
                  <span className="text-slate-500 font-medium truncate mr-3 max-w-[180px]">
                    {item.product.title}
                  </span>
                  <span className="font-bold text-slate-700 whitespace-nowrap">
                    {(getUnitPrice(item) * item.quantity).toLocaleString()} ETB
                  </span>
                </div>
              ))}
            </div>

            <div className="flex justify-between items-center mb-6">
              <span className="text-sm font-bold text-slate-500">Subtotal</span>
              <span className="text-2xl font-black text-slate-950">
                {subtotal.toLocaleString()} <span className="text-xs font-bold text-slate-400">ETB</span>
              </span>
            </div>

            <p className="text-[11px] text-slate-400 font-medium mb-5">
              Shipping, taxes, and import fees will be calculated at checkout. Credit terms apply if eligible.
            </p>

            {profile && !profile.isVerified && (
              <div className="flex items-start gap-2.5 text-amber-700 text-xs font-semibold mb-4 bg-amber-500/10 border border-amber-500/20 rounded-xl p-3.5">
                <AlertCircle size={16} className="text-amber-600 shrink-0 mt-0.5" />
                <span>Your B2B account is pending verification. You can browse the catalog and place orders via direct online payment (Chapa), but credit terms are disabled until verified.</span>
              </div>
            )}

            <button
              onClick={() => navigate("/b2b/checkout")}
              className="w-full h-14 rounded-2xl font-black uppercase tracking-wider text-sm flex items-center justify-center gap-3 transition-all bg-blue-600 text-white hover:bg-blue-700 shadow-lg shadow-blue-200"
            >
              Proceed to Checkout <ArrowRight size={18} />
            </button>
          </div>
        </div>
      </div>
    </B2bLayout>
  );
};

export default B2bCart;
